APPENDS = {
    "README.md": '\n\n<!-- ANGULAR_FRONTEND_PHASE_0_CONTRACTS -->\n## Angular frontend Phase 0 contracts\n\nThe current FastAPI surface is now captured as an executable, commit-pinned\ncontract inventory for the planned Angular workplace-agent UI. Phase 0 adds no\nvisual frontend and does not pretend that conversation persistence or streaming\nalready exists.\n\nSee `frontend/README.md` and validate with:\n\n```bash\npython scripts/validate_frontend_contracts.py --repo .\npytest -q tests/test_frontend_contracts.py\n```\n',
    "APPLY_AND_VALIDATE.md": '\n\n<!-- ANGULAR_FRONTEND_PHASE_0_VALIDATION -->\n## Angular frontend Phase 0 validation\n\n```powershell\npython scripts/validate_frontend_contracts.py --repo .\npytest -q tests/test_frontend_contracts.py\npython -m compileall -q scripts tests\npytest -q\ngit diff --check\n```\n\nExpected contract surface: 31 unique public endpoint method/path pairs and 13\nvalidated synthetic examples. No Angular runtime or fake streaming behavior is\nintroduced in this phase.\n',
}
ANCHORS = {
    "app/api/agent_routes.py": ("/{organization_id}/agent/query",),
    "app/api/action_routes.py": ("/{organization_id}/agent/actions/propose", "rollback-proposal", "audit-replay"),
    "app/api/health_routes.py": ('EXPECTED_MIGRATION_HEAD = "0015_workplace_workflows"', "/workplace/capabilities"),
    "app/schemas/agent_actions.py": ("restore_workplace_resource_snapshots",),
    "app/core/errors.py": ("X-Request-Id", '"agent_action_stale"'),
}


def run(repo: Path, *args: str, check: bool = True) -> subprocess.CompletedProcess[str]:
    return subprocess.run(
        list(args),
        cwd=repo,
        check=check,
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
    )


def git(repo: Path, *args: str) -> str:
    return run(repo, "git", *args).stdout.strip()


def verify_repo(repo: Path) -> None:
    root = Path(git(repo, "rev-parse", "--show-toplevel")).resolve()
    if root != repo:
        raise RuntimeError("Run from the repository root or pass --repo.")
    branch = git(repo, "branch", "--show-current")
    if branch != EXPECTED_BRANCH:
        raise RuntimeError(f"Expected branch {EXPECTED_BRANCH}, found {branch}.")
    head = git(repo, "rev-parse", "HEAD")
    if head != EXPECTED_HEAD:
        raise RuntimeError(f"Expected HEAD {EXPECTED_HEAD}, found {head}.")
    origin = git(repo, "remote", "get-url", "origin")
    normalized = origin.removesuffix(".git").replace("git@github.com:", "https://github.com/")
    if not normalized.endswith(EXPECTED_REPOSITORY):
        raise RuntimeError(f"Unexpected origin: {origin}")
    tracked = git(repo, "status", "--porcelain", "--untracked-files=no")
    if tracked:
        raise RuntimeError("Tracked working tree must be clean before applying Phase 0.")
    for relative, required in ANCHORS.items():
        path = repo / relative
        if not path.is_file():
            raise RuntimeError(f"Missing required source file: {relative}")
        text = path.read_text(encoding="utf-8")
        for anchor in required:
            if anchor not in text:
                raise RuntimeError(f"Source anchor not found in {relative}: {anchor}")
    for relative in FILES:
        if (repo / relative).exists():
            raise RuntimeError(f"Target already exists: {relative}")
    for relative, addition in APPENDS.items():
        path = repo / relative
        if not path.is_file():
            raise RuntimeError(f"Missing append target: {relative}")
        marker = addition.splitlines()[2]
        if marker in path.read_text(encoding="utf-8"):
            raise RuntimeError(f"Phase 0 marker already exists in {relative}")


def write_atomic(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    temporary = path.with_name(path.name + ".phase0.tmp")
    try:
        temporary.write_text(content.rstrip() + "\n", encoding="utf-8", newline="\n")
        os.replace(temporary, path)
    finally:
        if temporary.exists():
            temporary.unlink()


def apply(repo: Path) -> None:
    created: list[Path] = []
    backups: dict[Path, bytes] = {}
    try:
        for relative, content in FILES.items():
            path = repo / relative
            write_atomic(path, content)
            created.append(path)
        for relative, addition in APPENDS.items():
            path = repo / relative
            backups[path] = path.read_bytes()
            original = path.read_text(encoding="utf-8").rstrip()
            write_atomic(path, original + addition)

        checks = [
            (sys.executable, "scripts/validate_frontend_contracts.py", "--repo", "."),
            (sys.executable, "-m", "pytest", "-q", "tests/test_frontend_contracts.py"),
            (sys.executable, "-m", "compileall", "-q", "scripts", "tests"),
            ("git", "diff", "--check"),
        ]
        for command in checks:
            result = run(repo, *command, check=False)
            if result.returncode != 0:
                raise RuntimeError(
                    "Post-apply validation failed: " + " ".join(command) + "\n" + result.stdout
                )
    except Exception:
        for path, content in backups.items():
            path.write_bytes(content)
        for path in reversed(created):
            if path.exists():
                path.unlink()
        for directory in sorted(
            {path.parent for path in created}, key=lambda item: len(item.parts), reverse=True
        ):
            try:
                directory.rmdir()
            except OSError:
                pass
        raise


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--repo", default=".")
    args = parser.parse_args()
    repo = Path(args.repo).resolve()
    verify_repo(repo)
    apply(repo)
    print("Angular frontend Phase 0 contracts applied successfully.")
    print("Created 24 contract, documentation, sample, validator and test files.")
    print("Validation passed: 31 endpoints and 13 examples.")
    print("No files were staged, committed or pushed.")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
